            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(viewResult.Model);
            Assert.NotEmpty(model);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.About();
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(viewResult.Model);

            // Students 2 and 3 share enrollment date 2021-09-01
            var group2021 = model.SingleOrDefault(g => g.EnrollmentDate == DateTime.Parse("2021-09-01"));
            Assert.NotNull(group2021);
            Assert.Equal(2, group2021.StudentCount);
        }

        [Fact]
        public void About_ReturnsEmptyList_WhenNoStudents()
        {
            var result = _controller.About();
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(viewResult.Model);
            Assert.Empty(model);
        }

        [Fact]
        public void Contact_ReturnsViewWithMessage()
        {
