            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("Your contact page.", _controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsView()
        {
            var result = _controller.Error();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            var result = _controller.Unauthorized();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new StudentsController(_context);

            // Setup TempData for actions that use it
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(), new SessionStateTempDataProvider(new SessionStateTempDataProviderOptions()));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithPaginatedStudents()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index(null, null, null, null);

            var model = Assert.IsType<PaginatedList<Student>>(((ViewResult)result).Model);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index("name_desc", null, null, null);

            var model = Assert.IsType<PaginatedList<Student>>(((ViewResult)result).Model);
            Assert.Equal("Anand", model[0].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index("Date", null, null, null);

            var model = Assert.IsType<PaginatedList<Student>>(((ViewResult)result).Model);
            Assert.Equal("Alexander", model[0].LastName); // 2020
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index("date_desc", null, null, null);

            var model = Assert.IsType<PaginatedList<Student>>(((ViewResult)result).Model);
            // 2021 students first
            Assert.True(model[0].EnrollmentDate >= model[1].EnrollmentDate);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersResults()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index(null, null, "Alexander", null);

            var model = Assert.IsType<PaginatedList<Student>>(((ViewResult)result).Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index(null, null, "Meredith", null);

            var model = Assert.IsType<PaginatedList<Student>>(((ViewResult)result).Model);
            Assert.Single(model);
            Assert.Equal("Alonso", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_ResetsPaging()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index(null, null, "Alexander", 5);

            // When a new search string is provided, page resets to 1
            var model = Assert.IsType<PaginatedList<Student>>(((ViewResult)result).Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            TestHelpers.SeedStudents(_context);

            var result = _controller.Index(null, "Alexander", null, null);

            var model = Assert.IsType<PaginatedList<Student>>(((ViewResult)result).Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            TestHelpers.SeedStudents(_context);

            _controller.Index("Date", null, "test", null);

            Assert.Equal("Date", _controller.ViewBag.CurrentSort);
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_EmptySortOrder_SetsNameSortParmToNameDesc()
        {
            TestHelpers.SeedStudents(_context);

            _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsStudentWithEnrollments()
        {
            TestHelpers.SeedFullData(_context);

            var result = _controller.Details(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("Alexander", model.LastName);
            Assert.NotNull(model.Enrollments);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithStudentDefaultDate()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-15")
            };

            var result = _controller.Create(student);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_SavesInDatabase()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-15")
            };

            _controller.Create(student);

            Assert.Equal(1, _context.Students.Count());
            Assert.Equal("Student", _context.Students.First().LastName);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student { EnrollmentDate = DateTime.Parse("2023-01-15") };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Student>(viewResult.Model);
        }

        [Fact]
        public void Create_Post_MinDateEnrollment_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_DateBeforeSqlMin_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
