        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();

            _tempWebRoot = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempWebRoot);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempWebRoot);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempWebRoot);

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempWebRoot))
            {
                try { Directory.Delete(_tempWebRoot, true); } catch { }
            }
        }

        private IFormFile CreateMockFile(string fileName, string content, long? length = null)
        {
            var bytes = Encoding.UTF8.GetBytes(content);
            var stream = new MemoryStream(bytes);
            var file = new Mock<IFormFile>();
            file.Setup(f => f.FileName).Returns(fileName);
            file.Setup(f => f.Length).Returns(length ?? bytes.Length);
            file.Setup(f => f.OpenReadStream()).Returns(stream);
            file.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => stream.CopyTo(s));
            return file.Object;
        }

