namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);

            // Drain static queue
            var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
            svc.Dispose();
        }

        public void Dispose()
        {
            // Drain static queue after tests
            var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
            svc.Dispose();

            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_ReturnsJsonResult()
        {
            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsSuccessTrue_WhenEmpty()
        {
            var result = _controller.GetNotifications();

            var jsonResult = Assert.IsType<JsonResult>(result);
            var value = jsonResult.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_ReturnsNotifications_WhenAvailable()
        {
            // Enqueue notifications via the service
            var svc = new NotificationService();
            svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");
            svc.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE, "Admin");
            svc.Dispose();

            var result = _controller.GetNotifications();

            var jsonResult = Assert.IsType<JsonResult>(result);
            var value = jsonResult.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.Equal(2, (int)countProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            var svc = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                svc.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }
            svc.Dispose();

            var result = _controller.GetNotifications();

            var jsonResult = Assert.IsType<JsonResult>(result);
            var value = jsonResult.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.Equal(10, (int)countProp.GetValue(value));
        }

        [Fact]
        public void MarkAsRead_ReturnsJsonWithSuccess()
        {
            var result = _controller.MarkAsRead(1);

            var jsonResult = Assert.IsType<JsonResult>(result);
            var value = jsonResult.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }
    }
}

