using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithInstructorIndexData()
        {
            TestHelpers.SeedFullData(_context);

            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotEmpty(model.Instructors);
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            TestHelpers.SeedFullData(_context);

            var result = _controller.Index(1, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
            Assert.NotEmpty(model.Courses);
        }

        [Fact]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            TestHelpers.SeedFullData(_context);

            var result = _controller.Index(1, 1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Index_NoSelection_HasNullCoursesAndEnrollments()
        {
            TestHelpers.SeedFullData(_context);

            var result = _controller.Index(null, null);

            var model = Assert.IsType<InstructorIndexData>(((ViewResult)result).Model);
            Assert.Null(model.Courses);
            Assert.Null(model.Enrollments);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsInstructor()
        {
            TestHelpers.SeedInstructors(_context);

            var result = _controller.Details(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", model.LastName);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.Empty(model.CourseAssignments);
        }

        [Fact]
        public void Create_Get_PopulatesAssignedCourseData()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.Create();

            Assert.NotNull(_controller.ViewBag.Courses);
            var courses = Assert.IsAssignableFrom<List<AssignedCourseData>>(_controller.ViewBag.Courses);
            Assert.Equal(2, courses.Count);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2023-01-15"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidInstructor_SavesInDatabase()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2023-01-15"),
                CourseAssignments = new List<CourseAssignment>()
            };

            _controller.Create(instructor, null);

            Assert.Equal(1, _context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            TestHelpers.SeedCourses(_context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2023-01-15"),
                CourseAssignments = new List<CourseAssignment>()
            };

            _controller.Create(instructor, new[] { "1050", "4022" });

            var saved = _context.Instructors.First();
            Assert.Equal(2, _context.CourseAssignments.Count(ca => ca.InstructorID == saved.ID));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor { HireDate = DateTime.Today, CourseAssignments = new List<CourseAssignment>() };

            var result = _controller.Create(instructor, null);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            TestHelpers.SeedFullData(_context);

            var result = _controller.Edit(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal("Abercrombie", model.LastName);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            TestHelpers.SeedInstructors(_context);

            var result = _controller.Delete(1);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Instructor>(viewResult.Model);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_RemovesInstructor()
        {
            TestHelpers.SeedFullData(_context);

            _controller.DeleteConfirmed(1);

            Assert.Null(_context.Instructors.Find(1));
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            TestHelpers.SeedFullData(_context);

            _controller.DeleteConfirmed(1);

            var dept = _context.Departments.First(d => d.DepartmentID == 1);
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            TestHelpers.SeedFullData(_context);

            var result = _controller.DeleteConfirmed(1);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        #endregion
    }
}

