using System;
using System.IO;
using System.Linq;
using System.Net;
using System.Text;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempWebRoot;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();

            _tempWebRoot = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempWebRoot);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempWebRoot);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempWebRoot);

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempWebRoot))
            {
                try { Directory.Delete(_tempWebRoot, true); } catch { }
            }
        }

        private IFormFile CreateMockFile(string fileName, string content, long? length = null)
        {
            var bytes = Encoding.UTF8.GetBytes(content);
            var stream = new MemoryStream(bytes);
            var file = new Mock<IFormFile>();
            file.Setup(f => f.FileName).Returns(fileName);
            file.Setup(f => f.Length).Returns(length ?? bytes.Length);
            file.Setup(f => f.OpenReadStream()).Returns(stream);
            file.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => stream.CopyTo(s));
            return file.Object;
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Index_EmptyDb_ReturnsEmptyList()
        {
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(viewResult.Model);
            Assert.Empty(model);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsCourse()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.Details(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            TestHelpers.SeedDepartments(_context);

            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
            Assert.IsType<Course>(viewResult.Model);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course
            {
                CourseID = 5555,
                Title = "Physics",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_SavesInDatabase()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course
            {
                CourseID = 5555,
                Title = "Physics",
                Credits = 3,
                DepartmentID = 1
            };

            _controller.Create(course, null);

            Assert.Equal(1, _context.Courses.Count());
        }

        [Fact]
        public void Create_Post_WithValidImage_UploadsFile()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course { CourseID = 5555, Title = "Physics", Credits = 3, DepartmentID = 1 };
            var file = CreateMockFile("test.jpg", "image-data");

            _controller.Create(course, file);

            var saved = _context.Courses.Find(5555);
            Assert.NotNull(saved.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_WithInvalidImageExtension_ReturnsViewWithError()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course { CourseID = 5555, Title = "Physics", Credits = 3, DepartmentID = 1 };
            var file = CreateMockFile("test.exe", "malicious-content");

            var result = _controller.Create(course, file);

            Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_WithTooLargeFile_ReturnsViewWithError()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course { CourseID = 5555, Title = "Physics", Credits = 3, DepartmentID = 1 };
            var file = CreateMockFile("test.jpg", "data", 6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, file);

            Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            TestHelpers.SeedDepartments(_context);
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course();

            var result = _controller.Create(course, null);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.Edit(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            TestHelpers.SeedCourses(_context);
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updated = new Course
            {
                CourseID = 1050,
                Title = "Advanced Chemistry",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Edit(updated, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_Post_WithValidImage_UploadsNewFile()
        {
            TestHelpers.SeedCourses(_context);
            var course = _context.Courses.Find(1050);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updated = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
            var file = CreateMockFile("new_image.png", "image-data");

            _controller.Edit(updated, file);

            var saved = _context.Courses.Find(1050);
            Assert.NotNull(saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void Edit_Post_WithInvalidImageExtension_ReturnsViewWithError()
        {
            TestHelpers.SeedCourses(_context);
            var updated = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
            var file = CreateMockFile("bad.txt", "text-content");

            var result = _controller.Edit(updated, file);

            Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_Post_WithTooLargeImage_ReturnsViewWithError()
        {
            TestHelpers.SeedCourses(_context);
            var updated = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
            var file = CreateMockFile("big.jpg", "data", 6 * 1024 * 1024);

            var result = _controller.Edit(updated, file);

            Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            TestHelpers.SeedCourses(_context);
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050 };

            var result = _controller.Edit(course, null);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsCourse()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.Delete(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Course>(viewResult.Model);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_RemovesCourse()
        {
            TestHelpers.SeedCourses(_context);

            _controller.DeleteConfirmed(1050);

            Assert.Null(_context.Courses.Find(1050));
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex()
        {
            TestHelpers.SeedCourses(_context);

            var result = _controller.DeleteConfirmed(1050);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_WithImage_DeletesFile()
        {
            TestHelpers.SeedCourses(_context);
            // Create a fake image file
            var uploadsDir = Path.Combine(_tempWebRoot, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var imagePath = Path.Combine(uploadsDir, "test.jpg");
            File.WriteAllText(imagePath, "test");

            var course = _context.Courses.Find(1050);
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test.jpg";
            _context.SaveChanges();

            _controller.DeleteConfirmed(1050);

            Assert.False(File.Exists(imagePath));
        }

        #endregion

        #region Image extension validation

        [Theory]
        [InlineData("test.jpg")]
        [InlineData("test.jpeg")]
        [InlineData("test.png")]
        [InlineData("test.gif")]
        [InlineData("test.bmp")]
        public void Create_Post_AcceptsValidImageExtensions(string fileName)
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course
            {
                CourseID = new Random().Next(10000, 99999),
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            };
            var file = CreateMockFile(fileName, "image-data");

            var result = _controller.Create(course, file);

            Assert.IsType<RedirectToActionResult>(result);
        }

        [Theory]
        [InlineData("test.pdf")]
        [InlineData("test.doc")]
        [InlineData("test.exe")]
        [InlineData("test.zip")]
        public void Create_Post_RejectsInvalidImageExtensions(string fileName)
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course { CourseID = 9999, Title = "Test", Credits = 3, DepartmentID = 1 };
            var file = CreateMockFile(fileName, "data");

            var result = _controller.Create(course, file);

            Assert.IsType<ViewResult>(result);
        }

        #endregion
    }
}

