using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First();
            Assert.Equal("Test", retrieved.FirstMidName);
            Assert.Equal("User", retrieved.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            Assert.Single(_context.Instructors);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            var department = new Department
            {
                Name = "Science",
                Budget = 500000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            _context.Departments.Add(department);
            _context.SaveChanges();

            Assert.Single(_context.Departments);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            TestHelpers.SeedDepartments(_context);
            var course = new Course
            {
                CourseID = 1001,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            };

            _context.Courses.Add(course);
            _context.SaveChanges();

            Assert.NotNull(_context.Courses.Find(1001));
        }

        [Fact]
        public void CanAddAndRetrieveEnrollment()
        {
            TestHelpers.SeedCourses(_context);
            TestHelpers.SeedStudents(_context);

            var enrollment = new Enrollment
            {
                StudentID = 1,
                CourseID = 1050,
                Grade = Grade.A
            };

            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            Assert.Single(_context.Enrollments);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            TestHelpers.SeedFullData(_context);

            var assignment = _context.CourseAssignments.Find(1050, 1);
            Assert.NotNull(assignment);
        }

        [Fact]
        public void CanAddNotification()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };

            _context.Notifications.Add(notification);
            _context.SaveChanges();

            Assert.Single(_context.Notifications);
        }

        [Fact]
        public void DbSets_AreNotNull()
        {
            Assert.NotNull(_context.Courses);
            Assert.NotNull(_context.Enrollments);
            Assert.NotNull(_context.Departments);
            Assert.NotNull(_context.OfficeAssignments);
            Assert.NotNull(_context.CourseAssignments);
            Assert.NotNull(_context.People);
            Assert.NotNull(_context.Students);
            Assert.NotNull(_context.Instructors);
            Assert.NotNull(_context.Notifications);
        }
    }
}

